import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd"; // User input containing path traversal sequence

        String baseDir = "/path/to/base/directory/";
        String fullPath = new File(baseDir, userInput).getCanonicalPath();

        if (!fullPath.startsWith(baseDir)) {
            System.out.println("Invalid path specified.");
            return;
        }

        try {
            File file = new File(fullPath);
            if (file.exists()) {
                byte[] fileContent = Files.readAllBytes(file.toPath());
                System.out.println(new String(fileContent));
            } else {
                System.out.println("File not found");
            }
        } catch (IOException e) {
            System.out.println("An error occurred while reading the file.");
            e.printStackTrace();
        }
    }
}

